import Taro from '@tarojs/taro';

// 后端地址：编译时自动注入局域网 IP（config/dev.ts）
// 真机预览时需要设置 LAN_IP 环境变量：LAN_IP=192.168.x.x npm run dev:weapp
const HOST = (typeof LAN_IP_DEFINE !== 'undefined' ? LAN_IP_DEFINE : '') || 'localhost';
export const BASE_URL = `http://${HOST}:3000`;

// 真机检测：非 devtools 平台且 HOST 为 localhost 时，视为离线模式
let _isRealDevice: boolean | null = null;
function isRealDeviceWithoutBackend(): boolean {
  if (_isRealDevice !== null) return _isRealDevice;
  try {
    const info = Taro.getSystemInfoSync();
    _isRealDevice = info.platform !== 'devtools' && HOST === 'localhost';
  } catch (_) {
    _isRealDevice = false;
  }
  return _isRealDevice;
}

let _token = '';

export function setToken(token: string) {
  _token = token;
  Taro.setStorageSync('token', token);
}

export function getToken(): string {
  if (_token) return _token;
  _token = Taro.getStorageSync('token') || '';
  return _token;
}

export function clearToken() {
  _token = '';
  Taro.removeStorageSync('token');
}

async function request<T>(opts: {
  url: string;
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE';
  data?: any;
}): Promise<T> {
  // 真机无后端时直接抛错，由上层 catch 走 demo fallback
  if (isRealDeviceWithoutBackend()) {
    throw new Error('OFFLINE: real device without backend connectivity');
  }

  try {
    const res = await Taro.request({
      url: `${BASE_URL}${opts.url}`,
      method: opts.method || 'GET',
      data: opts.data,
      header: {
        'Content-Type': 'application/json',
        ...(getToken() ? { Authorization: `Bearer ${getToken()}` } : {}),
      },
    });

    if (res.statusCode === 401) {
      clearToken();
      throw new Error('登录已过期，请重新登录');
    }

    if (res.statusCode >= 400) {
      const msg = (res.data as any)?.message || `HTTP ${res.statusCode}`;
      throw new Error(msg);
    }

    const body = res.data as any;
    if (body.code !== 0) {
      throw new Error(body.message || `错误码: ${body.code}`);
    }

    return body.data as T;
  } catch (e: any) {
    if (e.errMsg && e.errMsg.includes('request:fail')) {
      throw new Error(`网络请求失败: ${e.errMsg}。请确认后端已启动 (${BASE_URL})`);
    }
    throw e;
  }
}

// ---- API 方法 ----

export async function login(code = 'mock', nickname?: string, inviteCode?: string) {
  if (isRealDeviceWithoutBackend()) {
    const token = 'demo_token_' + Date.now();
    setToken(token);
    return { token, user: { userId: 'demo-user', nickName: nickname || '行者' }, bindMsg: null };
  }
  try {
    const data = await request<{ token: string; user: any; bindMsg?: string }>({
      url: '/api/auth/login',
      method: 'POST',
      data: { code, nickname, manualInviteCode: inviteCode },
    });
    setToken(data.token);
    return data;
  } catch (_) {
    const token = 'demo_token_' + Date.now();
    setToken(token);
    return { token, user: { userId: 'demo-user', nickName: nickname || '行者' }, bindMsg: null };
  }
}

