/**
 * 上传录音文件
 * @returns { audioUrl, fileSize, originalName }
 */
export async function uploadAudio(filePath: string, duration: number) {
  const token = getToken();
  if (!token) throw new Error('未登录');

  try {
    const res = await Taro.uploadFile({
      url: `${BASE_URL}/api/diary/upload-audio`,
      filePath,
      name: 'file',
      formData: { duration: String(duration) },
      header: { Authorization: `Bearer ${token}` },
    });

    const body = JSON.parse(res.data) as any;
    if (body.code !== 0) {
      throw new Error(body.message || '上传失败');
    }
    return body.data as { audioUrl: string; fileSize: number; originalName: string };
  } catch (e: any) {
    if (e.errMsg && e.errMsg.includes('uploadFile:fail')) {
      throw new Error(`上传失败: ${e.errMsg}。请确认后端已启动。`);
    }
    throw e;
  }
}

/**
 * 创建录音文件识别任务
 */
export async function createTranscribeTask(audioUrl: string) {
  return request<{ taskId: number }>({
    url: '/api/speech/transcribe',
    method: 'POST',
    data: { audioUrl },
  });
}

/**
 * 查询识别任务状态
 * status: 0=等待, 1=执行中, 2=成功
 */
export async function queryTaskStatus(taskId: number) {
  return request<{ status: number; text: string }>({
    url: `/api/speech/task-status/${taskId}`,
  });
}

/**
 * 轮询直到识别完成
 * @param taskId 任务 ID
 * @param maxRetries 最大轮询次数（默认 20 次，每 2s 一次 = 40s）
 */
export async function pollTranscribe(taskId: number, maxRetries = 20): Promise<string> {
  for (let i = 0; i < maxRetries; i++) {
    await new Promise((r) => setTimeout(r, 2000));
    const result = await queryTaskStatus(taskId);

    if (result.status === 2) {
      return result.text || '';
    }
    if (result.status === 3) {
      throw new Error('语音识别失败');
    }
    // status 0/1: 继续等待
  }
  throw new Error('识别超时，请手动输入');
}

