import Taro from '@tarojs/taro';
import { setToken } from './api';

const CONSENT_KEY = 'xingzhe_user_consent';
const INVITER_KEY = 'xingzhe_pending_inviter';
const LOC_KEY = 'xingzhe_location_granted';

// ---- Location Lock ----

export function isLocationGranted(): boolean {
  return Taro.getStorageSync(LOC_KEY) === '1';
}

export function setLocationGranted(v: boolean) {
  Taro.setStorageSync(LOC_KEY, v ? '1' : '0');
}

// ---- User Consent ----

export function getConsent(): boolean {
  return Taro.getStorageSync(CONSENT_KEY) === '1';
}

export function setConsent(agreed: boolean) {
  Taro.setStorageSync(CONSENT_KEY, agreed ? '1' : '0');
}

// ---- Invite Chain ----

export function storePendingInviter(inviterId: string) {
  if (!inviterId) return;
  Taro.setStorageSync(INVITER_KEY, inviterId);
}

export function consumePendingInviter(): string | undefined {
  const id = Taro.getStorageSync(INVITER_KEY);
  if (id) {
    Taro.removeStorageSync(INVITER_KEY);
    return id;
  }
  return undefined;
}

const CITY_KEY = 'xingzhe_city';
const DEFAULT_CITY = '';
// ---- City ----

export function getSavedCity(): string {
  return Taro.getStorageSync(CITY_KEY) || DEFAULT_CITY;
}

export function setSavedCity(city: string) {
  Taro.setStorageSync(CITY_KEY, city);
}

// ---- Demo phone login (production: wx.getPhoneNumber → backend decrypt) ----

/**
 * Complete phone-based login.
 * On real device without backend, creates a demo token.
 * Inviter ID is consumed from the share link chain.
 */
export async function doLogin(inviteCode?: string) {
  const BASE_URL = (typeof LAN_IP_DEFINE !== 'undefined' ? LAN_IP_DEFINE : '') || 'localhost';
  const apiBase = `http://${BASE_URL}:3000`;

  // Consume inviter from share link
  const pendingInviter = consumePendingInviter();
  const finalCode = inviteCode || pendingInviter || undefined;

  const isRealDevice = (() => {
    try {
      const info = Taro.getSystemInfoSync();
      return info.platform !== 'devtools';
    } catch (_) { return false; }
  })();

  if (isRealDevice) {
    // Real device: generate demo token
    const token = 'demo_token_' + Date.now();
    setToken(token);
    return {
      token,
      user: { userId: 'demo-user', nickName: '微信用户', avatarUrl: '' },
      bindMsg: finalCode ? '邀请关系已建立' : null,
    };
  }

  // DevTools: call backend
  try {
    const res = await Taro.request({
      url: `${apiBase}/api/auth/login`,
      method: 'POST',
      header: { 'Content-Type': 'application/json' },
      data: { code: 'phone_mock_' + Date.now(), nickname: '微信用户', manualInviteCode: finalCode },
    });
    const body = res.data as any;
    if (body.code === 0 && body.data?.token) {
      setToken(body.data.token);
      return body.data;
    }
    throw new Error(body.message || '登录失败');
  } catch (e: any) {
    if (e.message?.includes('request:fail')) {
      // Backend unreachable — demo fallback
      const token = 'demo_token_' + Date.now();
      setToken(token);
      return {
        token,
        user: { userId: 'demo-user', nickName: '微信用户', avatarUrl: '' },
        bindMsg: finalCode ? '邀请关系已建立' : null,
      };
    }
    throw e;
  }
}
